INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'de9ae60d-c786-408b-8103-10d4c62c8108',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jenkins Pipeline Stages — Enforcing Fail Fast with lint → test → build → deploy$escape$,
  $escape$Jenkins Declarative Pipelines enforce fail-fast by default: if any stage exits non-zero, downstream stages are skipped and the build is marked FAILURE. Structure your stages in ascending cost order — lint first (cheapest), then test, then build artifacts, then deploy — so expensive work never runs on broken code.

Use `failFast: true` inside a `parallel` block to abort sibling branches the moment one fails. For the lint stage, wire in your actual tool (e.g. `sh 'npm run lint -- --max-warnings 0'`) so warnings become hard errors. Gate the deploy stage with a `when { branch 'main' }` condition so feature branches never accidentally push to production.

Stash build artifacts between stages with `stash`/`unstash` rather than rebuilding — Jenkins agents don't share a workspace by default. Use `post { always { junit 'reports/**/*.xml' } }` to surface test results even on failure, giving you signal without re-running the pipeline. Keep each stage's `sh` calls focused; fat stages hide the failure point and slow down red-to-fix feedback loops.$escape$,
  $escape$pipeline {
  agent any
  stages {
    stage('Lint') {
      steps { sh 'npm run lint -- --max-warnings 0' }
    }
    stage('Test') {
      steps { sh 'npm test -- --ci' }
      post { always { junit 'reports/jest/*.xml' } }
    }
    stage('Build') {
      steps {
        sh 'npm run build'
        stash name: 'dist', includes: 'dist/**'
      }
    }
    stage('Deploy') {
      when { branch 'main' }
      steps {
        unstash 'dist'
        sh './scripts/deploy.sh'
      }
    }
  }
}$escape$,
  $escape$bash$escape$,
