INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '478cd95c-d964-4991-8da3-6f35c31968ad',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jenkins Secrets Done Right — Credentials Plugin, Vault Integration, and What to Never Do$escape$,
  $escape$Hardcoding credentials in a Jenkinsfile is a critical misconfig — they end up in SCM history and console logs. Jenkins' built-in Credentials Plugin is your first line of defense. Store secrets as `Secret text`, `Username with password`, or `Secret file` in Manage Jenkins → Credentials, then bind them in-pipeline using `withCredentials`. For external secret management, the HashiCorp Vault Plugin lets Jenkins authenticate via AppRole or Kubernetes service accounts and fetch secrets at runtime — secrets never touch the Jenkins database. Declare vault bindings with `vault secrets: [...]` in your `withVault` block. For environment-scoped secrets, prefer folder-level or pipeline-level credential scoping over global credentials to enforce least privilege. Always set `VAULT_SKIP_VERIFY=false` in production. One often-missed detail: Jenkins masks bound credentials in console output, but only for the exact string — base64-encoded variants will still leak. Use `credentials()` in `environment {}` blocks for implicit masking across all steps, not just inside `withCredentials`.$escape$,
  $escape$pipeline {
  agent any
  environment {
    DEPLOY_TOKEN = credentials('deploy-token-id')
  }
  stages {
    stage('Deploy') {
      steps {
        withVault(vaultSecrets: [[path: 'secret/prod/db', secretValues: [
          [envVar: 'DB_PASS', vaultKey: 'password']
        ]]]) {
          sh 'deploy.sh --db-pass "$DB_PASS" --token "$DEPLOY_TOKEN"'
        }
      }
    }
  }
}$escape$,
  $escape$bash$escape$,
