INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e0c33261-1842-4836-a1ba-59a63c885e33',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jenkins Preview Environments — Ephemeral PRs with Automatic Teardown$escape$,
  $escape$Jenkins Multibranch Pipelines expose `env.CHANGE_ID` for every pull request branch, making per-PR preview environments straightforward. Use a `when { changeRequest() }` guard to restrict deploy logic to PRs only, then namespace your environment with `preview-${env.CHANGE_ID}` so multiple PRs never collide.

Deploy in the `Build` or `Deploy` stage using that namespace — whether you're running `kubectl apply -n preview-${env.CHANGE_ID}`, spinning up a Docker Compose stack, or provisioning a Kubernetes namespace via Helm with `--namespace pr-${env.CHANGE_ID}`.

Teardown belongs in a `post { cleanup }` block on the PR branch, not the `always` block — `cleanup` runs regardless of build outcome but only after all other post conditions. When the PR merges, the Multibranch plugin deletes the branch and triggers a final run of the Jenkinsfile with `currentBuild.result` available, letting you conditionally skip teardown on failure. Pair with the GitHub Branch Source plugin's `Discard old builds` and `Prune stale branches` settings so orphaned environments don't persist if Jenkins misses a merge event.$escape$,
  $escape$pipeline {
  agent any
  stages {
    stage('Deploy Preview') {
      when { changeRequest() }
      steps {
        sh "helm upgrade --install pr-${env.CHANGE_ID} ./chart --namespace pr-${env.CHANGE_ID} --create-namespace --set image.tag=${env.GIT_COMMIT[0..6]}"
        echo "Preview: https://pr-${env.CHANGE_ID}.preview.example.com"
      }
    }
  }
  post {
    cleanup {
      script {
        if (env.CHANGE_ID) {
          sh "helm uninstall pr-${env.CHANGE_ID} --namespace pr-${env.CHANGE_ID} || true"
          sh "kubectl delete namespace pr-${env.CHANGE_ID} --ignore-not-found"
        }
      }
    }
  }
}$escape$,
  $escape$bash$escape$,
