INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1b0ce729-be9f-4b3b-806c-11395848aa12',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jenkins Notifications — Failure Alerts, Status Badges, and Incident Escalation$escape$,
  $escape$Jenkins' built-in post block in Declarative Pipelines gives you granular notification hooks: always, failure, unstable, fixed, and regression. Pair this with the Email Extension Plugin (emailext) or Slack Notification Plugin to fire targeted alerts. For status badges on your repo, the Embeddable Build Status Plugin exposes a URL like /buildStatus/icon?job=my-pipeline&build=last that returns a real-time SVG — embed it directly in your README. For incident escalation, chain notification steps using currentBuild.previousBuild.result: if the previous build also failed, escalate to PagerDuty via an HTTP POST using the httpRequest step rather than a simple Slack ping. The Jenkins Monitoring Plugin (JavaMelody) and the Prometheus Metrics Plugin expose /prometheus for scraping — wire build failure rates into Grafana alerts for team-wide SLO visibility. Always include BUILD_URL, JOB_NAME, and BUILD_NUMBER in notification payloads so on-call engineers can jump directly to the console log without hunting through the UI.$escape$,
  $escape$pipeline {
  agent any
  post {
    failure {
      script {
        def isRecurring = currentBuild.previousBuild?.result == 'FAILURE'
        if (isRecurring) {
          httpRequest(
            url: 'https://events.pagerduty.com/v2/enqueue',
            httpMode: 'POST',
            contentType: 'APPLICATION_JSON',
            requestBody: """{"routing_key":"${PAGERDUTY_KEY}","event_action":"trigger","payload":{"summary":"${JOB_NAME} failing repeatedly","severity":"critical","source":"${BUILD_URL}"}}"""
          )
        } else {
          slackSend channel: '#alerts', color: 'danger',
            message: "FAILED: ${JOB_NAME} #${BUILD_NUMBER} — ${BUILD_URL}"
        }
      }
    }
    fixed {
      slackSend channel: '#alerts', color: 'good',
        message: "RECOVERED: ${JOB_NAME} #${BUILD_NUMBER}"
    }
  }
}$escape$,
  $escape$bash$escape$,
